var C, delayF, delayWordF, opaAdj, delayF, masterDelay, childDelay, delayStart, delayF, delay;
C = thisComp.layer('variW1 404');
delayF = 2;
$bm_rt = delayWordF = 0;
if (C.effect('variW Control')('opacity') == true) {
    opaAdj = C.effect('variW Control')('opacity adjust');
    if (C.effect('variW Control')('delay per word') == true)
        delayF = delayWordF;
    masterDelay = C.effect('variW Control')('master delay');
    childDelay = C.effect('variW Control')('opacity delay');
    delayStart = $bm_sub(C.effect('variW Control')('delay start index'), 1);
    delayF = Math.abs($bm_sub(delayStart, delayF));
    delay = $bm_mul(framesToTime($bm_sum(childDelay, masterDelay)), delayF);
    $bm_rt = $bm_sum(value, opaAdj.valueAtTime($bm_sub(time, delay)));
} else
    $bm_rt = value;

