var $bm_rt;
var C, delayF, delayWordF, v, delayTime, delayTime, delayStart, delayTime, posAdj, masterDelay, childDelay, delay, v, tracking, trackingDelay, delay, v;
C = thisComp.layer('variW1 404');
delayF = 2;
delayWordF = 0;
v = [
    0,
    0
];
if (C.effect('variW Control')('delay per word') == true)
    delayTime = delayWordF;
else
    delayTime = delayF;
delayStart = $bm_sub(C.effect('variW Control')('delay start index'), 1);
delayTime = Math.abs($bm_sub(delayStart, delayTime));
if (C.effect('variW Control')('position') == true) {
    posAdj = C.effect('variW Control')('position adjust');
    masterDelay = C.effect('variW Control')('master delay');
    childDelay = C.effect('variW Control')('position delay');
    delay = $bm_mul(framesToTime($bm_sum(childDelay, masterDelay)), delayTime);
    v = posAdj.valueAtTime($bm_sub(time, delay));
}
if (C.effect('variW Control')('tracking') == true) {
    tracking = C.effect('variW Control')('tracking adjust');
    trackingDelay = C.effect('variW Control')('tracking delay (no master)');
    delay = $bm_mul(framesToTime(trackingDelay), delayTime);
    v = $bm_sum(v, [
        $bm_div($bm_mul(value[0], tracking.valueAtTime($bm_sub(time, delay))), 100),
        0
    ]);
}
$bm_rt = $bm_sum(value, v);

