$bm_rt = delayWordF = 0;
if (C.effect('variW Control')('scale') == true) {
    scaleAdj = C.effect('variW Control')('scale adjust');
    if (C.effect('variW Control')('delay per word') == true)
        delayF = delayWordF;
    masterDelay = C.effect('variW Control')('master delay');
    childDelay = C.effect('variW Control')('scale delay');
    delayStart = $bm_sub(C.effect('variW Control')('delay start index'), 1);
    delayF = Math.abs($bm_sub(delayStart, delayF));
    delay = $bm_mul(framesToTime($bm_sum(childDelay, masterDelay)), delayF);
    $bm_rt = factor = $bm_div(scaleAdj.valueAtTime($bm_sub(time, delay)), 100);
    if (C.effect('variW Control')('scale linked') == false) {
